class DisjointSet:
    def __init__(self):
        self.parent = {}

    def make_set(self, x):
        if x not in self.parent:
            self.parent[x] = x

    def find(self, x):
        if x not in self.parent:
            raise ValueError(f"Element {x} not found. Call make_set({x}) first.")

        if self.parent[x] == x:
            return x

        # Path compression
        self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        root_x = self.find(x)
        root_y = self.find(y)

        if root_x != root_y:
            self.parent[root_y] = root_x
            return True
        return False
